#!/usr/bin/env node
// My HVAC Tech Patch — Claim Flow + Google Verification + Add Contractor Fix
const fs = require("fs");
const path = require("path");
const PROJECT_ROOT = process.cwd();
const files = {};

files["supabase/migrations/007_claim_requests.sql"] = "";
files["src/lib/types.ts"] = "";
files["src/app/api/claim-request/route.ts"] = "";
files["src/app/api/admin/claims/route.ts"] = "";
files["src/app/api/admin/contractors/route.ts"] = "";
files["src/app/for-contractors/claim/[slug]/page.tsx"] = "";
files["src/app/for-contractors/claim/[slug]/ClaimListingClient.tsx"] = "";
files["src/app/contractors/[slug]/page.tsx"] = "";
files["src/app/admin/claims/page.tsx"] = "";
files["src/app/admin/layout.tsx"] = "";
files["src/app/(auth)/login/page.tsx"] = "";
files["src/app/(auth)/signup/page.tsx"] = "";
files["src/app/layout.tsx"] = "";


let created = 0, updated = 0;
for (const [relPath, b64] of Object.entries(files)) {
  const fullPath = path.join(PROJECT_ROOT, relPath);
  const dir = path.dirname(fullPath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
    console.log("  📁 Created dir:", dir.replace(PROJECT_ROOT + "/", ""));
  }
  const existed = fs.existsSync(fullPath);
  fs.writeFileSync(fullPath, Buffer.from(b64, "base64").toString("utf-8"));
  if (existed) { updated++; console.log("  ✏️  Updated:", relPath); }
  else { created++; console.log("  ✨ Created:", relPath); }
}
console.log("");
console.log(`✅ Patch applied: ${created} created, ${updated} updated (${created+updated} total files)`);
console.log("");
console.log("📋 NEXT STEPS:");
console.log("  1. Run BOTH migrations in Supabase SQL Editor:");
console.log("     • supabase/migrations/006_google_reviews.sql  (if not already run)");
console.log("     • supabase/migrations/007_claim_requests.sql");
console.log("");
console.log("  2. Git push:");
console.log('     git add . && git commit -m "feat: claim flow + google verification + add contractor fix" && git push');
console.log("");
